from collections import deque

def trace_curve(grid, start_block, line_color, all_block_cells):
    """Trace a curve from a 2x2 block through line-color cells to another block.
    Returns the set of line cells on the path and the endpoint block."""
    H, W = grid.shape
    r, c = start_block
    block_cells_start = {(r,c), (r+1,c), (r,c+1), (r+1,c+1)}

    # Find adjacent line cells
    queue = deque()
    visited = set()

    for br, bc in block_cells_start:
        for dr, dc in [(-1,0),(1,0),(0,-1),(0,1)]:
            nr, nc = br+dr, bc+dc
            if 0 <= nr < H and 0 <= nc < W and (nr,nc) not in block_cells_start:
                if grid[nr,nc] == line_color:
                    queue.append((nr,nc))
                    visited.add((nr,nc))

    line_cells = set(visited)
    reached_blocks = set()

    while queue:
        cr, cc = queue.popleft()
        for dr, dc in [(-1,0),(1,0),(0,-1),(0,1)]:
            nr, nc = cr+dr, cc+dc
            if 0 <= nr < H and 0 <= nc < W and (nr,nc) not in visited and (nr,nc) not in block_cells_start:
                if grid[nr,nc] == line_color:
                    visited.add((nr,nc))
                    line_cells.add((nr,nc))
                    queue.append((nr,nc))
                elif (nr,nc) in all_block_cells and all_block_cells[(nr,nc)] != start_block:
                    # Reached another block
                    reached_blocks.add(all_block_cells[(nr,nc)])

    return line_cells, reached_blocks

