    # 1. Find background color (most common)
    bg = int(np.argmax(np.bincount(grid.flatten())))

    # 2. Find 3 non-bg colors
    colors = sorted(set(int(x) for x in np.unique(grid)) - {bg})

    # 3. Identify LINE, MINORITY, MAJORITY by number of 8-connected components
    color_comps = {}
    for c in colors:
        mask = grid == c
        labeled, n = ndimage.label(mask, structure=np.ones((3,3)))
        color_comps[c] = (n, labeled)

    sorted_colors = sorted(colors, key=lambda c: color_comps[c][0])
    minority_color = sorted_colors[0]  # fewest components (2)
    majority_color = sorted_colors[1]  # middle
    line_color = sorted_colors[2]      # most components

    # 4. Get labeled components
    _, line_labeled = color_comps[line_color]
    _, min_labeled = color_comps[minority_color]
    _, maj_labeled = color_comps[majority_color]

    n_line = int(line_labeled.max())
    n_min = int(min_labeled.max())

    # 5. For each line component, find adjacent block clusters
    def get_cluster_adjacency(line_comp_id):
        adjacent = set()
        coords = np.argwhere(line_labeled == line_comp_id)
        for r, c in coords:
            for dr in range(-1, 2):
                for dc in range(-1, 2):
                    nr, nc = r + dr, c + dc
                    if 0 <= nr < H and 0 <= nc < W:
                        if grid[nr, nc] == minority_color:
                            adjacent.add(('min', int(min_labeled[nr, nc])))
                        elif grid[nr, nc] == majority_color:
                            adjacent.add(('maj', int(maj_labeled[nr, nc])))
        return adjacent

    # 6. Build graph
    adj_list = defaultdict(list)
    for i in range(1, n_line + 1):
        adj = list(get_cluster_adjacency(i))
        if len(adj) == 2:
            adj_list[adj[0]].append((adj[1], i))
            adj_list[adj[1]].append((adj[0], i))
        elif len(adj) > 2:
            for a in range(len(adj)):
                for b in range(a + 1, len(adj)):
                    adj_list[adj[a]].append((adj[b], i))
                    adj_list[adj[b]].append((adj[a], i))

    # 7. BFS shortest path between minority clusters
    min_clusters = [('min', i) for i in range(1, n_min + 1)]
    start, end = min_clusters[0], min_clusters[1]

    queue = deque([(start, [start], [])])
    visited = {start}
    path_found = None

    while queue:
        node, path, edge_ids = queue.popleft()
        if node == end:
            path_found = (path, edge_ids)
            break
        for neighbor, comp_id in adj_list[node]:
            if neighbor not in visited:
                visited.add(neighbor)
                queue.append((neighbor, path + [neighbor], edge_ids + [comp_id]))

    # 8. Apply changes
    output = grid.copy()
    if path_found:
        path, edge_ids = path_found
        for comp_id in edge_ids:
            output[line_labeled == comp_id] = 5
        for node in path:
            if node[0] == 'maj':
                output[maj_labeled == node[1]] = 3

    return output.tolist()

